INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'מסגרות ברזל', '**דלת ממ"ד - מסגרת ברזל לא אטומה** — מסגרת דלת הממ"ד אינה אטומה - רווחים בין המסגרת לקיר, גומי האיטום חסר או פגום. הממ"ד לא יספק הגנה כנדרש.. המלצה: החלפת גומי האיטום, מילוי רווחים בין המסגרת לקיר בחומר אטימה מתאים. עלות משוערת: ₪500-₪1200 (ליחידה)', '**דלת ממ"ד - מסגרת ברזל לא אטומה** — מסגרת דלת הממ"ד אינה אטומה - רווחים בין המסגרת לקיר, גומי האיטום חסר או פגום. הממ"ד לא יספק הגנה כנדרש.. המלצה: החלפת גומי האיטום, מילוי רווחים בין המסגרת לקיר בחומר אטימה מתאים. עלות משוערת: ₪500-₪1200 (ליחידה)', 'ת"י 4766 — דלת ממ"ד חייבת להיות אטומה לגזים ולעמוד בלחץ פיצוץ, כולל גומי איטום תקין בהיקף המסגרת', 'ת"י 4766 — דלת ממ"ד חייבת להיות אטומה לגזים ולעמוד בלחץ פיצוץ, כולל גומי איטום תקין בהיקף המסגרת', true, 'critical');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'מסגרות ברזל', '**דלת ממ"ד - ברגי נעילה לא מתפקדים** — ברגי הנעילה של דלת הממ"ד (קרמונים) אינם נכנסים לשקעים במשקוף, קשים להפעלה, או חסרים. הדלת לא ניתנת לנעילה אטומה.. המלצה: שימון/תיקון ברגי הנעילה, כוונון שקעי המשקוף, החלפת חלקים פגומים. עלות משוערת: ₪300-₪800 (ליחידה)', '**דלת ממ"ד - ברגי נעילה לא מתפקדים** — ברגי הנעילה של דלת הממ"ד (קרמונים) אינם נכנסים לשקעים במשקוף, קשים להפעלה, או חסרים. הדלת לא ניתנת לנעילה אטומה.. המלצה: שימון/תיקון ברגי הנעילה, כוונון שקעי המשקוף, החלפת חלקים פגומים. עלות משוערת: ₪300-₪800 (ליחידה)', 'ת"י 4766 — דלת ממ"ד חייבת להיות ניתנת לנעילה אטומה באמצעות ברגי נעילה תקינים', 'ת"י 4766 — דלת ממ"ד חייבת להיות ניתנת לנעילה אטומה באמצעות ברגי נעילה תקינים', true, 'critical');
