INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'מסגרות ברזל', '**חלון ממ"ד - סגר פלדה חסר או פגום** — סגר הפלדה (שאטר) של חלון הממ"ד חסר, תקוע, או לא נסגר עד הסוף. החלון לא יספק הגנה בעת חירום.. המלצה: שימון מנגנון הסגר, תיקון פסי ההחלקה, החלפת סגר פגום. עלות משוערת: ₪500-₪1500 (ליחידה)', '**חלון ממ"ד - סגר פלדה חסר או פגום** — סגר הפלדה (שאטר) של חלון הממ"ד חסר, תקוע, או לא נסגר עד הסוף. החלון לא יספק הגנה בעת חירום.. המלצה: שימון מנגנון הסגר, תיקון פסי ההחלקה, החלפת סגר פגום. עלות משוערת: ₪500-₪1500 (ליחידה)', 'ת"י 4766 — סגר פלדה של חלון ממ"ד חייב להיות תקין, ניתן לסגירה ונעילה מלאה', 'ת"י 4766 — סגר פלדה של חלון ממ"ד חייב להיות תקין, ניתן לסגירה ונעילה מלאה', true, 'critical');
