INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'מעקות', '**גובה מעקה מרפסת נמוך מהנדרש** — גובה מעקה המרפסת נמוך מ-105 ס"מ (עד קומה 4) או נמוך מ-120 ס"מ (מעל קומה 4). סכנת נפילה מגובה.. המלצה: הגבהת המעקה לגובה התקני על ידי הוספת מאריך או החלפת המעקה. עלות משוערת: ₪800-₪2000 (למ"א)', '**גובה מעקה מרפסת נמוך מהנדרש** — גובה מעקה המרפסת נמוך מ-105 ס"מ (עד קומה 4) או נמוך מ-120 ס"מ (מעל קומה 4). סכנת נפילה מגובה.. המלצה: הגבהת המעקה לגובה התקני על ידי הוספת מאריך או החלפת המעקה. עלות משוערת: ₪800-₪2000 (למ"א)', 'ת"י 1142 — גובה מעקה מינימלי: 105 ס"מ עד גובה 12 מ'' (קומה 4), 120 ס"מ מעל 12 מ''', 'ת"י 1142 — גובה מעקה מינימלי: 105 ס"מ עד גובה 12 מ'' (קומה 4), 120 ס"מ מעל 12 מ''', true, 'critical');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'מעקות', '**מרווח בין אלמנטים במעקה גדול מ-10 ס"מ** — המרווח בין אלמנטים אנכיים (שבכות/פסים) במעקה גדול מ-10 ס"מ. ילד קטן עלול לתחוב את ראשו בין הפסים.. המלצה: הוספת פסים אנכיים או רשת נוספת לצמצום המרווחים ל-10 ס"מ מקסימום. עלות משוערת: ₪500-₪1500 (למ"א)', '**מרווח בין אלמנטים במעקה גדול מ-10 ס"מ** — המרווח בין אלמנטים אנכיים (שבכות/פסים) במעקה גדול מ-10 ס"מ. ילד קטן עלול לתחוב את ראשו בין הפסים.. המלצה: הוספת פסים אנכיים או רשת נוספת לצמצום המרווחים ל-10 ס"מ מקסימום. עלות משוערת: ₪500-₪1500 (למ"א)', 'ת"י 1142 — מרווח מקסימלי בין אלמנטים במעקה: 10 ס"מ בכל כיוון', 'ת"י 1142 — מרווח מקסימלי בין אלמנטים במעקה: 10 ס"מ בכל כיוון', true, 'critical');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'מעקות', '**מעקה מרפסת לא יציב - מתנדנד** — מעקה המרפסת מתנדנד בלחיצה, עיגון לריצפה או לקיר לא מספק. המעקה אינו עומד בעומס האופקי הנדרש.. המלצה: חיזוק עיגון המעקה - תיקון עוגנים, ריתוך מחדש, או החלפת נקודות עיגון. עלות משוערת: ₪600-₪1500 (למ"א)', '**מעקה מרפסת לא יציב - מתנדנד** — מעקה המרפסת מתנדנד בלחיצה, עיגון לריצפה או לקיר לא מספק. המעקה אינו עומד בעומס האופקי הנדרש.. המלצה: חיזוק עיגון המעקה - תיקון עוגנים, ריתוך מחדש, או החלפת נקודות עיגון. עלות משוערת: ₪600-₪1500 (למ"א)', 'ת"י 1142 — מעקה חייב לעמוד בעומס אופקי של 100 ק"ג/מ'' ללא עיוות קבוע', 'ת"י 1142 — מעקה חייב לעמוד בעומס אופקי של 100 ק"ג/מ'' ללא עיוות קבוע', true, 'critical');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'מעקות', '**חלודה ושיתוך במעקה ברזל** — סימני חלודה והתקלפות צבע במעקה ברזל. חלודה מתקדמת מחלישה את המעקה ומקצרה את חייו.. המלצה: שיוף החלודה, מריחת ציפוי נגד חלודה (פריימר), וצביעה מחדש בצבע עמיד לחוץ. עלות משוערת: ₪200-₪500 (למ"א)', '**חלודה ושיתוך במעקה ברזל** — סימני חלודה והתקלפות צבע במעקה ברזל. חלודה מתקדמת מחלישה את המעקה ומקצרה את חייו.. המלצה: שיוף החלודה, מריחת ציפוי נגד חלודה (פריימר), וצביעה מחדש בצבע עמיד לחוץ. עלות משוערת: ₪200-₪500 (למ"א)', NULL, NULL, true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'מעקות', '**ריתוך פגום במעקה ברזל** — ריתוכים במעקה עם סדקים, חורים, או ריתוך חלקי. ריתוך פגום מחליש את המעקה ועלול לגרום לקריסה.. המלצה: ריתוך מחדש של כל נקודות הריתוך הפגומות על ידי רתך מוסמך, בדיקה ויזואלית. עלות משוערת: ₪300-₪800 (למ"א)', '**ריתוך פגום במעקה ברזל** — ריתוכים במעקה עם סדקים, חורים, או ריתוך חלקי. ריתוך פגום מחליש את המעקה ועלול לגרום לקריסה.. המלצה: ריתוך מחדש של כל נקודות הריתוך הפגומות על ידי רתך מוסמך, בדיקה ויזואלית. עלות משוערת: ₪300-₪800 (למ"א)', 'ת"י 1142 — ריתוכים במעקה חייבים להיות רציפים, ללא סדקים או חסרים, ולעמוד בעומסים הנדרשים', 'ת"י 1142 — ריתוכים במעקה חייבים להיות רציפים, ללא סדקים או חסרים, ולעמוד בעומסים הנדרשים', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'מעקות', '**מעקה עם אלמנט טיפוס (ladder effect)** — מעקה עם פסים אופקיים או אלמנטים המאפשרים לילד לטפס. עיצוב המעקה חייב למנוע אפשרות טיפוס.. המלצה: החלפת אלמנטים אופקיים בפסים אנכיים, או הוספת לוח חיפוי שימנע טיפוס. עלות משוערת: ₪800-₪2000 (למ"א)', '**מעקה עם אלמנט טיפוס (ladder effect)** — מעקה עם פסים אופקיים או אלמנטים המאפשרים לילד לטפס. עיצוב המעקה חייב למנוע אפשרות טיפוס.. המלצה: החלפת אלמנטים אופקיים בפסים אנכיים, או הוספת לוח חיפוי שימנע טיפוס. עלות משוערת: ₪800-₪2000 (למ"א)', 'ת"י 1142 — מעקה לא יכלול אלמנטים המאפשרים טיפוס, פסים אופקיים חייבים להיות צפופים או אנכיים בלבד', 'ת"י 1142 — מעקה לא יכלול אלמנטים המאפשרים טיפוס, פסים אופקיים חייבים להיות צפופים או אנכיים בלבד', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'מעקות', '**מעקה מדרגות חסר או לא רציף** — מעקה בגרם מדרגות חסר בצד אחד או שני הצדדים, או שאינו רציף לאורך כל גרם המדרגות. סכנת נפילה.. המלצה: התקנת מעקה/מסעד רציף לאורך כל גרם המדרגות בהתאם לרוחב. עלות משוערת: ₪1000-₪2500 (למ"א)', '**מעקה מדרגות חסר או לא רציף** — מעקה בגרם מדרגות חסר בצד אחד או שני הצדדים, או שאינו רציף לאורך כל גרם המדרגות. סכנת נפילה.. המלצה: התקנת מעקה/מסעד רציף לאורך כל גרם המדרגות בהתאם לרוחב. עלות משוערת: ₪1000-₪2500 (למ"א)', 'ת"י 1142 — גרם מדרגות ברוחב עד 110 ס"מ חייב מעקה/מסעד בצד אחד לפחות, מעל 110 ס"מ - בשני צדדים', 'ת"י 1142 — גרם מדרגות ברוחב עד 110 ס"מ חייב מעקה/מסעד בצד אחד לפחות, מעל 110 ס"מ - בשני צדדים', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'מעקות', '**מסעד (handrail) בגובה לא תקני** — גובה המסעד במדרגות לא בטווח התקני (85-100 ס"מ מקצה המדרגה). גובה לא נכון מפחית את היעילות הבטיחותית.. המלצה: התאמת גובה המסעד לטווח התקני 85-100 ס"מ. עלות משוערת: ₪500-₪1200 (למ"א)', '**מסעד (handrail) בגובה לא תקני** — גובה המסעד במדרגות לא בטווח התקני (85-100 ס"מ מקצה המדרגה). גובה לא נכון מפחית את היעילות הבטיחותית.. המלצה: התאמת גובה המסעד לטווח התקני 85-100 ס"מ. עלות משוערת: ₪500-₪1200 (למ"א)', 'ת"י 1142 — גובה מסעד במדרגות: 85-100 ס"מ מקצה המדרגה עד ראש המסעד', 'ת"י 1142 — גובה מסעד במדרגות: 85-100 ס"מ מקצה המדרגה עד ראש המסעד', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'מעקות', '**מעקה גג ללא גובה מינימלי** — מעקה בגג נגיש (גג שימושי) בגובה נמוך מ-120 ס"מ. סכנת נפילה חמורה מגובה הבניין.. המלצה: הגבהת מעקה הגג לגובה מינימלי 120 ס"מ בהתאם לתקן. עלות משוערת: ₪1000-₪2500 (למ"א)', '**מעקה גג ללא גובה מינימלי** — מעקה בגג נגיש (גג שימושי) בגובה נמוך מ-120 ס"מ. סכנת נפילה חמורה מגובה הבניין.. המלצה: הגבהת מעקה הגג לגובה מינימלי 120 ס"מ בהתאם לתקן. עלות משוערת: ₪1000-₪2500 (למ"א)', 'ת"י 1142 — מעקה בגג נגיש חייב להיות בגובה מינימלי של 120 ס"מ', 'ת"י 1142 — מעקה בגג נגיש חייב להיות בגובה מינימלי של 120 ס"מ', true, 'critical');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'מעקות', '**מעקה מרפסת - חוסר ציפוי גלוון** — מעקה ברזל ללא ציפוי גלוון (אבץ חם) כנדרש לאלמנטים חיצוניים. ללא גלוון המעקה יחלוד במהירות.. המלצה: פירוק המעקה, טבילה בגלוון חם, והתקנה מחדש. לחלופין - שיוף וציפוי בצבע אפוקסי דו-רכיבי. עלות משוערת: ₪600-₪1500 (למ"א)', '**מעקה מרפסת - חוסר ציפוי גלוון** — מעקה ברזל ללא ציפוי גלוון (אבץ חם) כנדרש לאלמנטים חיצוניים. ללא גלוון המעקה יחלוד במהירות.. המלצה: פירוק המעקה, טבילה בגלוון חם, והתקנה מחדש. לחלופין - שיוף וציפוי בצבע אפוקסי דו-רכיבי. עלות משוערת: ₪600-₪1500 (למ"א)', NULL, NULL, true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'איטום — גג', '**חוסר יריעת איטום בגג שטוח** — לא בוצע איטום בגג שטוח או שיריעת האיטום חסרה לחלוטין. חשיפת מרכיבי הגג לחדירת מים ישירה, גורמת לנזקי רטיבות קשים במבנה.. המלצה: התקנת מערכת איטום מלאה כולל יריעת איטום ביטומנית דו-שכבתית, פריימר, וחיפוי הגנה. עלות משוערת: ₪120-₪200 (למ"ר)', '**חוסר יריעת איטום בגג שטוח** — לא בוצע איטום בגג שטוח או שיריעת האיטום חסרה לחלוטין. חשיפת מרכיבי הגג לחדירת מים ישירה, גורמת לנזקי רטיבות קשים במבנה.. המלצה: התקנת מערכת איטום מלאה כולל יריעת איטום ביטומנית דו-שכבתית, פריימר, וחיפוי הגנה. עלות משוערת: ₪120-₪200 (למ"ר)', 'ת"י 931 — גגות שטוחים חייבים איטום מלא בהתאם לתקן, כולל יריעת איטום ביטומנית או סינתטית עם חפיפות תקניות', 'ת"י 931 — גגות שטוחים חייבים איטום מלא בהתאם לתקן, כולל יריעת איטום ביטומנית או סינתטית עם חפיפות תקניות', true, 'critical');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'איטום — גג', '**קרעים ונקבים ביריעת איטום הגג** — נצפו קרעים, חורים או נקבים ביריעת האיטום בגג השטוח, כתוצאה מפגיעה מכנית, תנועה תרמית או ביצוע לקוי. מאפשרים חדירת מים למבנה.. המלצה: תיקון נקודתי באמצעות טלאי יריעת איטום בגודל מינימלי של 30x30 ס"מ עם חפיפה של 10 ס"מ לכל כיוון, או החלפת יריעה באזור הפגוע. עלות משוערת: ₪250-₪800 (ליחידה)', '**קרעים ונקבים ביריעת איטום הגג** — נצפו קרעים, חורים או נקבים ביריעת האיטום בגג השטוח, כתוצאה מפגיעה מכנית, תנועה תרמית או ביצוע לקוי. מאפשרים חדירת מים למבנה.. המלצה: תיקון נקודתי באמצעות טלאי יריעת איטום בגודל מינימלי של 30x30 ס"מ עם חפיפה של 10 ס"מ לכל כיוון, או החלפת יריעה באזור הפגוע. עלות משוערת: ₪250-₪800 (ליחידה)', 'ת"י 931 — יריעת האיטום חייבת להיות רציפה ושלמה, ללא קרעים או נקבים', 'ת"י 931 — יריעת האיטום חייבת להיות רציפה ושלמה, ללא קרעים או נקבים', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'איטום — גג', '**חפיפה לא תקנית בין יריעות איטום** — חפיפות בין יריעות האיטום קטנות מהנדרש בתקן (פחות מ-10 ס"מ באורך ו-15 ס"מ ברוחב), או שהחפיפות לא הולחמו כראוי. מהווה נקודת כשל לחדירת מים.. המלצה: פירוק החפיפה הפגומה והרחבתה לגודל תקני עם הלחמה מחודשת בלהבה או אוויר חם. עלות משוערת: ₪80-₪150 (למ"א)', '**חפיפה לא תקנית בין יריעות איטום** — חפיפות בין יריעות האיטום קטנות מהנדרש בתקן (פחות מ-10 ס"מ באורך ו-15 ס"מ ברוחב), או שהחפיפות לא הולחמו כראוי. מהווה נקודת כשל לחדירת מים.. המלצה: פירוק החפיפה הפגומה והרחבתה לגודל תקני עם הלחמה מחודשת בלהבה או אוויר חם. עלות משוערת: ₪80-₪150 (למ"א)', 'ת"י 1637 — חפיפת יריעות ביטומניות: מינימום 10 ס"מ באורך ו-15 ס"מ ברוחב, עם הלחמה מלאה', 'ת"י 1637 — חפיפת יריעות ביטומניות: מינימום 10 ס"מ באורך ו-15 ס"מ ברוחב, עם הלחמה מלאה', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'איטום — גג', '**העדר כיפוף (קרניז) איטום בשפת הגג** — יריעת האיטום לא עולה על המעקה/חומה היקפית בגובה מינימלי של 25 ס"מ. מאפשר חדירת מים בנקודת המפגש בין הגג למעקה.. המלצה: הארכת יריעת האיטום על המעקה לגובה של 25 ס"מ לפחות, כולל עיגון מכני בראש הכיפוף וסרגל לחיצה. עלות משוערת: ₪60-₪120 (למ"א)', '**העדר כיפוף (קרניז) איטום בשפת הגג** — יריעת האיטום לא עולה על המעקה/חומה היקפית בגובה מינימלי של 25 ס"מ. מאפשר חדירת מים בנקודת המפגש בין הגג למעקה.. המלצה: הארכת יריעת האיטום על המעקה לגובה של 25 ס"מ לפחות, כולל עיגון מכני בראש הכיפוף וסרגל לחיצה. עלות משוערת: ₪60-₪120 (למ"א)', 'ת"י 931 — יריעת האיטום חייבת לעלות על שפת הגג/מעקה בגובה מינימלי של 25 ס"מ מעל מפלס הגג המוגמר', 'ת"י 931 — יריעת האיטום חייבת לעלות על שפת הגג/מעקה בגובה מינימלי של 25 ס"מ מעל מפלס הגג המוגמר', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'איטום — גג', '**שיפוע לא תקני בגג שטוח** — שיפוע הגג השטוח קטן מ-1.5% הנדרש בתקן, גורם לשלוליות מים עומדים המזרזים התבלות יריעת האיטום ומגבירים סיכון לחדירת מים.. המלצה: יצירת שכבת שיפוע חדשה מבטון קל או תערובת שיפוע, והנחת מערכת איטום חדשה מעליה. עלות משוערת: ₪150-₪280 (למ"ר)', '**שיפוע לא תקני בגג שטוח** — שיפוע הגג השטוח קטן מ-1.5% הנדרש בתקן, גורם לשלוליות מים עומדים המזרזים התבלות יריעת האיטום ומגבירים סיכון לחדירת מים.. המלצה: יצירת שכבת שיפוע חדשה מבטון קל או תערובת שיפוע, והנחת מערכת איטום חדשה מעליה. עלות משוערת: ₪150-₪280 (למ"ר)', 'ת"י 931 — שיפוע מינימלי בגג שטוח: 1.5% לכיוון הניקוז', 'ת"י 931 — שיפוע מינימלי בגג שטוח: 1.5% לכיוון הניקוז', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'איטום — גג', '**סתימה או כשל במערכת ניקוז הגג** — מרזבים, נקזים או מפלטי מים בגג סתומים, שבורים או בקוטר לא מספיק. גורם להצטברות מים על הגג ולהגברת הלחץ ההידרוסטטי על האיטום.. המלצה: ניקוי ושחרור מערכת הניקוז, החלפת אלמנטים פגומים, התקנת מסנני עלים, ובדיקת קוטר נקזים מספיק. עלות משוערת: ₪500-₪2500 (ליחידה)', '**סתימה או כשל במערכת ניקוז הגג** — מרזבים, נקזים או מפלטי מים בגג סתומים, שבורים או בקוטר לא מספיק. גורם להצטברות מים על הגג ולהגברת הלחץ ההידרוסטטי על האיטום.. המלצה: ניקוי ושחרור מערכת הניקוז, החלפת אלמנטים פגומים, התקנת מסנני עלים, ובדיקת קוטר נקזים מספיק. עלות משוערת: ₪500-₪2500 (ליחידה)', 'ת"י 931 — מערכת ניקוז גג חייבת לפנות מים ביעילות, עם מספר נקזים מספק ושיפוע מתאים', 'ת"י 931 — מערכת ניקוז גג חייבת לפנות מים ביעילות, עם מספר נקזים מספק ושיפוע מתאים', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'איטום — גג', '**פריחה (blistering) ביריעת איטום ביטומנית** — נצפו בועות ותפיחויות (פריחה) ביריעת האיטום הביטומנית, כתוצאה מלחות כלואה מתחת ליריעה שמתאדה בחום. מחלישה את הצמדות היריעה ומובילה לקריעה.. המלצה: חיתוך הבועות בצורת X, ייבוש המשטח, הלחמה מחדש והנחת טלאי יריעה מעל באמצעות להבה. עלות משוערת: ₪150-₪400 (ליחידה)', '**פריחה (blistering) ביריעת איטום ביטומנית** — נצפו בועות ותפיחויות (פריחה) ביריעת האיטום הביטומנית, כתוצאה מלחות כלואה מתחת ליריעה שמתאדה בחום. מחלישה את הצמדות היריעה ומובילה לקריעה.. המלצה: חיתוך הבועות בצורת X, ייבוש המשטח, הלחמה מחדש והנחת טלאי יריעה מעל באמצעות להבה. עלות משוערת: ₪150-₪400 (ליחידה)', 'ת"י 1637 — יריעות ביטומניות חייבות להיות מודבקות באופן מלא למצע, ללא בועות אוויר או לחות כלואה', 'ת"י 1637 — יריעות ביטומניות חייבות להיות מודבקות באופן מלא למצע, ללא בועות אוויר או לחות כלואה', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'איטום — גג', '**כיווץ והתנתקות יריעת איטום סינתטית** — יריעת איטום סינתטית (EPDM/TPO/PVC) התכווצה ונמשכה מקצוות הגג או מנקודות עיגון, חושפת אזורים ללא הגנת איטום.. המלצה: הרחבת היריעה בחזרה למיקומה עם תוספת יריעה בקצוות, או החלפת היריעה באזור הפגוע. עלות משוערת: ₪100-₪180 (למ"ר)', '**כיווץ והתנתקות יריעת איטום סינתטית** — יריעת איטום סינתטית (EPDM/TPO/PVC) התכווצה ונמשכה מקצוות הגג או מנקודות עיגון, חושפת אזורים ללא הגנת איטום.. המלצה: הרחבת היריעה בחזרה למיקומה עם תוספת יריעה בקצוות, או החלפת היריעה באזור הפגוע. עלות משוערת: ₪100-₪180 (למ"ר)', 'ת"י 931 — יריעת איטום חייבת לכסות את כל שטח הגג ברציפות, כולל שוליים וכיפופים', 'ת"י 931 — יריעת איטום חייבת לכסות את כל שטח הגג ברציפות, כולל שוליים וכיפופים', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'איטום — גג', '**איטום לקוי בנקודת חיבור גג-קיר** — מפגש יריעת האיטום עם הקיר ההיקפי לא בוצע כראוי — חסר כיפוף, חסר סרגל לחיצה, או חסרה אטימה עליונה. נקודת חדירת מים נפוצה.. המלצה: ביצוע כיפוף תקני של יריעת האיטום על הקיר בגובה 25 ס"מ, התקנת סרגל לחיצה מגולוון ואטימה בפוליאוריתן. עלות משוערת: ₪70-₪140 (למ"א)', '**איטום לקוי בנקודת חיבור גג-קיר** — מפגש יריעת האיטום עם הקיר ההיקפי לא בוצע כראוי — חסר כיפוף, חסר סרגל לחיצה, או חסרה אטימה עליונה. נקודת חדירת מים נפוצה.. המלצה: ביצוע כיפוף תקני של יריעת האיטום על הקיר בגובה 25 ס"מ, התקנת סרגל לחיצה מגולוון ואטימה בפוליאוריתן. עלות משוערת: ₪70-₪140 (למ"א)', 'ת"י 931 — מפגש גג-קיר דורש כיפוף יריעת איטום עם עיגון מכני וסרגל לחיצה, ואטימה עליונה בחומר אלסטי', 'ת"י 931 — מפגש גג-קיר דורש כיפוף יריעת איטום עם עיגון מכני וסרגל לחיצה, ואטימה עליונה בחומר אלסטי', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'איטום — גג', '**רעפים שבורים או חסרים בגג רעפים** — רעפים שבורים, סדוקים או חסרים בגג משופע, חושפים את שכבת האיטום התחתית או ישירות את תת-הגג לחדירת מים ורוח.. המלצה: החלפת רעפים שבורים/חסרים ברעפים תואמים, בדיקת חפיפות ועיגון הרעפים שמסביב. עלות משוערת: ₪80-₪200 (ליחידה)', '**רעפים שבורים או חסרים בגג רעפים** — רעפים שבורים, סדוקים או חסרים בגג משופע, חושפים את שכבת האיטום התחתית או ישירות את תת-הגג לחדירת מים ורוח.. המלצה: החלפת רעפים שבורים/חסרים ברעפים תואמים, בדיקת חפיפות ועיגון הרעפים שמסביב. עלות משוערת: ₪80-₪200 (ליחידה)', 'ת"י 931 — כיסוי גג רעפים חייב להיות שלם ורציף, כל רעף פגום יוחלף', 'ת"י 931 — כיסוי גג רעפים חייב להיות שלם ורציף, כל רעף פגום יוחלף', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'איטום — גג', '**חוסר יריעת תת-רעפים** — לא הותקנה יריעת תת-רעפים (secondary membrane) מתחת לרעפים. בהיעדרה, מים שחודרים בין הרעפים מגיעים ישירות למבנה.. המלצה: הסרת הרעפים, התקנת יריעת תת-רעפים תקנית על הלטים, והחזרת הרעפים. עלות משוערת: ₪130-₪220 (למ"ר)', '**חוסר יריעת תת-רעפים** — לא הותקנה יריעת תת-רעפים (secondary membrane) מתחת לרעפים. בהיעדרה, מים שחודרים בין הרעפים מגיעים ישירות למבנה.. המלצה: הסרת הרעפים, התקנת יריעת תת-רעפים תקנית על הלטים, והחזרת הרעפים. עלות משוערת: ₪130-₪220 (למ"ר)', 'ת"י 931 — גג רעפים נדרשת שכבת הגנה משנית (יריעת תת-רעפים) להגנה מפני חדירת מים ורוח', 'ת"י 931 — גג רעפים נדרשת שכבת הגנה משנית (יריעת תת-רעפים) להגנה מפני חדירת מים ורוח', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'איטום — גג', '**איטום לקוי בשלחם (flashing) גג משופע** — שלחם (flashing) מפח מגולוון או עופרת באזורי מפגש גג-קיר, ארובות או חדירות — מנותק, חלוד או חסר. מאפשר חדירת מים בנקודות המפגש.. המלצה: החלפת השלחם הפגום בשלחם חדש מפח מגולוון או אלומיניום, עם חפיפות תקניות ואטימה בסיליקון. עלות משוערת: ₪150-₪500 (למ"א)', '**איטום לקוי בשלחם (flashing) גג משופע** — שלחם (flashing) מפח מגולוון או עופרת באזורי מפגש גג-קיר, ארובות או חדירות — מנותק, חלוד או חסר. מאפשר חדירת מים בנקודות המפגש.. המלצה: החלפת השלחם הפגום בשלחם חדש מפח מגולוון או אלומיניום, עם חפיפות תקניות ואטימה בסיליקון. עלות משוערת: ₪150-₪500 (למ"א)', 'ת"י 931 — כל מפגש גג-קיר וחדירה בגג משופע חייב שלחם תקני עם חפיפה מספקת', 'ת"י 931 — כל מפגש גג-קיר וחדירה בגג משופע חייב שלחם תקני עם חפיפה מספקת', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'איטום — גג', '**איטום לקוי בתפר התפשטות** — תפר ההתפשטות במבנה (בגג, ברצפה או בקירות) לא אטום כראוי או שחומר האיטום התבלה. מאפשר חדירת מים דרך התפר.. המלצה: הסרת חומר מילוי ישן, ניקוי התפר, התקנת חבל גיבוי (backer rod) ומילוי בחומר אטימה פוליאוריתני או סיליקוני גמיש. עלות משוערת: ₪80-₪200 (למ"א)', '**איטום לקוי בתפר התפשטות** — תפר ההתפשטות במבנה (בגג, ברצפה או בקירות) לא אטום כראוי או שחומר האיטום התבלה. מאפשר חדירת מים דרך התפר.. המלצה: הסרת חומר מילוי ישן, ניקוי התפר, התקנת חבל גיבוי (backer rod) ומילוי בחומר אטימה פוליאוריתני או סיליקוני גמיש. עלות משוערת: ₪80-₪200 (למ"א)', 'ת"י 938 — תפרי התפשטות חייבים מילוי גמיש תקני המסוגל לספוג תנועות תרמיות ומכניות תוך שמירה על אטימות', 'ת"י 938 — תפרי התפשטות חייבים מילוי גמיש תקני המסוגל לספוג תנועות תרמיות ומכניות תוך שמירה על אטימות', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'איטום — גג', '**נזק לאיטום גג מהתקנת מערכת סולארית** — התקנת פאנלים סולאריים על הגג פגעה ביריעת האיטום — קידוחים ללא אטימה, משקולות שמועכות את היריעה, או כבלים שיוצרים שחיקה.. המלצה: תיקון כל נקודות הפגיעה, התקנת כריות הגנה מתחת למשקולות, אטימת קידוחים בחומר אלסטומרי, ובדיקת שלמות האיטום. עלות משוערת: ₪1500-₪5000 (ליחידה)', '**נזק לאיטום גג מהתקנת מערכת סולארית** — התקנת פאנלים סולאריים על הגג פגעה ביריעת האיטום — קידוחים ללא אטימה, משקולות שמועכות את היריעה, או כבלים שיוצרים שחיקה.. המלצה: תיקון כל נקודות הפגיעה, התקנת כריות הגנה מתחת למשקולות, אטימת קידוחים בחומר אלסטומרי, ובדיקת שלמות האיטום. עלות משוערת: ₪1500-₪5000 (ליחידה)', 'ת"י 931 — כל חדירה או עומס על מערכת האיטום חייב להיות מתוכנן ומבוצע ללא פגיעה ברציפות האיטום', 'ת"י 931 — כל חדירה או עומס על מערכת האיטום חייב להיות מתוכנן ומבוצע ללא פגיעה ברציפות האיטום', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'איטום — גג', '**התבלות יריעת איטום מקרינת UV** — יריעת האיטום חשופה ישירות לקרינת שמש ללא שכבת הגנה (חצץ, ריצוף, או צבע מגן). היריעה מתייבשת, מתפוררת ומאבדת גמישות.. המלצה: הנחת שכבת הגנה על האיטום: חצץ שטוף בעובי 5 ס"מ, או ריצוף על פלטות, או מריחת צבע מגן רפלקטיבי. עלות משוערת: ₪40-₪120 (למ"ר)', '**התבלות יריעת איטום מקרינת UV** — יריעת האיטום חשופה ישירות לקרינת שמש ללא שכבת הגנה (חצץ, ריצוף, או צבע מגן). היריעה מתייבשת, מתפוררת ומאבדת גמישות.. המלצה: הנחת שכבת הגנה על האיטום: חצץ שטוף בעובי 5 ס"מ, או ריצוף על פלטות, או מריחת צבע מגן רפלקטיבי. עלות משוערת: ₪40-₪120 (למ"ר)', 'ת"י 1637 — יריעות ביטומניות הנחשפות לשמש חייבות שכבת הגנה עליונה: חצץ, אריחים, או ציפוי רפלקטיבי', 'ת"י 1637 — יריעות ביטומניות הנחשפות לשמש חייבות שכבת הגנה עליונה: חצץ, אריחים, או ציפוי רפלקטיבי', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'איטום — גג', '**מרזב גג שבור או מנותק** — מרזב הגג שבור, מנותק, או בשיפוע שגוי. מים גולשים מעבר למרזב ופוגעים בחזית הבניין, ביסודות ובאיטום.. המלצה: תיקון או החלפת מקטעי מרזב פגומים, כיוון שיפוע 0.5% לכיוון מוריד המים, חיזוק אוחזים. עלות משוערת: ₪80-₪200 (למ"א)', '**מרזב גג שבור או מנותק** — מרזב הגג שבור, מנותק, או בשיפוע שגוי. מים גולשים מעבר למרזב ופוגעים בחזית הבניין, ביסודות ובאיטום.. המלצה: תיקון או החלפת מקטעי מרזב פגומים, כיוון שיפוע 0.5% לכיוון מוריד המים, חיזוק אוחזים. עלות משוערת: ₪80-₪200 (למ"א)', NULL, NULL, true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'איטום — גג', '**מוריד מים (צנרת אנכית) מנותק או סתום** — מוריד מים מהגג מנותק מהמרזב, סתום בפסולת, או חסר בחלקו. מים מהגג שופכים על חזית הבניין וגורמים לנזקי רטיבות.. המלצה: חיבור מחדש או החלפת מוריד המים, ניקוי סתימות, והתקנת מסנן עלים בראש המוריד. עלות משוערת: ₪300-₪1000 (ליחידה)', '**מוריד מים (צנרת אנכית) מנותק או סתום** — מוריד מים מהגג מנותק מהמרזב, סתום בפסולת, או חסר בחלקו. מים מהגג שופכים על חזית הבניין וגורמים לנזקי רטיבות.. המלצה: חיבור מחדש או החלפת מוריד המים, ניקוי סתימות, והתקנת מסנן עלים בראש המוריד. עלות משוערת: ₪300-₪1000 (ליחידה)', NULL, NULL, true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'איטום — גג', '**פגיעה באיטום גג עקב צמחייה** — צמחייה (עשבים, שורשים, אצות) צומחת על או דרך יריעת האיטום בגג. שורשים חודרים ליריעה ויוצרים נקבים, ולחות מצטברת מתחתם.. המלצה: הסרת צמחייה ושורשים, תיקון נקבים ביריעת האיטום, ניקוי מערכת הניקוז, ותחזוקה שוטפת. עלות משוערת: ₪500-₪2000 (ליחידה)', '**פגיעה באיטום גג עקב צמחייה** — צמחייה (עשבים, שורשים, אצות) צומחת על או דרך יריעת האיטום בגג. שורשים חודרים ליריעה ויוצרים נקבים, ולחות מצטברת מתחתם.. המלצה: הסרת צמחייה ושורשים, תיקון נקבים ביריעת האיטום, ניקוי מערכת הניקוז, ותחזוקה שוטפת. עלות משוערת: ₪500-₪2000 (ליחידה)', 'ת"י 931 — יש לשמור על גג נקי מצמחייה ופסולת, ולוודא שמערכת האיטום שלמה', 'ת"י 931 — יש לשמור על גג נקי מצמחייה ופסולת, ולוודא שמערכת האיטום שלמה', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'איטום — גג', '**חוסר שכבת הפרדה בין איטום לבטון** — יריעת האיטום הונחה ישירות על בטון מחוספס ללא שכבת הפרדה (פריימר/ביטומן מדולל). גורם להצמדות חלקית ולנקודות כשל.. המלצה: באזורים בעייתיים — הרמת היריעה, מריחת פריימר, והדבקה מחדש. בגג חדש — ביצוע מלא עם פריימר. עלות משוערת: ₪15-₪30 (למ"ר)', '**חוסר שכבת הפרדה בין איטום לבטון** — יריעת האיטום הונחה ישירות על בטון מחוספס ללא שכבת הפרדה (פריימר/ביטומן מדולל). גורם להצמדות חלקית ולנקודות כשל.. המלצה: באזורים בעייתיים — הרמת היריעה, מריחת פריימר, והדבקה מחדש. בגג חדש — ביצוע מלא עם פריימר. עלות משוערת: ₪15-₪30 (למ"ר)', 'ת"י 1637 — חובה למרוח פריימר ביטומני על משטח הבטון לפני הנחת יריעת איטום ביטומנית', 'ת"י 1637 — חובה למרוח פריימר ביטומני על משטח הבטון לפני הנחת יריעת איטום ביטומנית', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'איטום — גג', '**חדירת מים בחיבור גג רעפים לארובה/מדחום** — חיבור גג הרעפים לארובה, מדחום או אלמנט בולט לא אטום כראוי. מים חודרים דרך נקודת החיבור בעיקר בגשם חזק.. המלצה: התקנת שלחם עופרת או אלומיניום בצורת שלב (stepped flashing) סביב הארובה, עם אטימה עליונה. עלות משוערת: ₪1500-₪4000 (ליחידה)', '**חדירת מים בחיבור גג רעפים לארובה/מדחום** — חיבור גג הרעפים לארובה, מדחום או אלמנט בולט לא אטום כראוי. מים חודרים דרך נקודת החיבור בעיקר בגשם חזק.. המלצה: התקנת שלחם עופרת או אלומיניום בצורת שלב (stepped flashing) סביב הארובה, עם אטימה עליונה. עלות משוערת: ₪1500-₪4000 (ליחידה)', 'ת"י 931 — כל חדירה או אלמנט בולט מגג רעפים חייב שלחם ואטימה ייעודית', 'ת"י 931 — כל חדירה או אלמנט בולט מגג רעפים חייב שלחם ואטימה ייעודית', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'איטום — מרפסות', '**חוסר איטום מרפסת — יריעה חסרה** — מרפסת חשופה ללא שכבת איטום מתחת לריצוף. מים חודרים דרך הריצוף והתשתית לתקרת הדירה מתחת.. המלצה: הסרת הריצוף, התקנת מערכת איטום מלאה (פריימר + יריעה ביטומנית או ציפוי פוליאוריתן), ריצוף מחדש. עלות משוערת: ₪250-₪450 (למ"ר)', '**חוסר איטום מרפסת — יריעה חסרה** — מרפסת חשופה ללא שכבת איטום מתחת לריצוף. מים חודרים דרך הריצוף והתשתית לתקרת הדירה מתחת.. המלצה: הסרת הריצוף, התקנת מערכת איטום מלאה (פריימר + יריעה ביטומנית או ציפוי פוליאוריתן), ריצוף מחדש. עלות משוערת: ₪250-₪450 (למ"ר)', 'ת"י 1556 — כל מרפסת חשופה חייבת מערכת איטום מלאה מתחת לריצוף, כולל כיפופים ושיפוע לניקוז', 'ת"י 1556 — כל מרפסת חשופה חייבת מערכת איטום מלאה מתחת לריצוף, כולל כיפופים ושיפוע לניקוז', true, 'critical');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'איטום — מרפסות', '**שיפוע לא תקני במרפסת** — שיפוע המרפסת לכיוון הניקוז קטן מ-1.5% או שהשיפוע לכיוון הפנים (כלפי הדירה) במקום כלפי חוץ. גורם להצטברות מים ולחדירתם למבנה.. המלצה: יצירת שכבת שיפוע מתקנת מבטון קל או דבק שיפוע, איטום מחדש וריצוף. עלות משוערת: ₪200-₪400 (למ"ר)', '**שיפוע לא תקני במרפסת** — שיפוע המרפסת לכיוון הניקוז קטן מ-1.5% או שהשיפוע לכיוון הפנים (כלפי הדירה) במקום כלפי חוץ. גורם להצטברות מים ולחדירתם למבנה.. המלצה: יצירת שכבת שיפוע מתקנת מבטון קל או דבק שיפוע, איטום מחדש וריצוף. עלות משוערת: ₪200-₪400 (למ"ר)', 'ת"י 1556 — שיפוע מרפסת מינימלי 1.5% לכיוון הניקוז, הרחק מפתח הדירה', 'ת"י 1556 — שיפוע מרפסת מינימלי 1.5% לכיוון הניקוז, הרחק מפתח הדירה', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'איטום — מרפסות', '**כיפוף איטום חסר בסף מרפסת** — יריעת האיטום לא עולה בכיפוף על הסף/מפתן בין המרפסת לחדר הפנימי. מים זורמים מתחת לסף וחודרים לדירה.. המלצה: הסרת הסף, ביצוע כיפוף יריעת איטום על מפתן הדלת, התקנת סף חדש עם אטימה. עלות משוערת: ₪800-₪2000 (ליחידה)', '**כיפוף איטום חסר בסף מרפסת** — יריעת האיטום לא עולה בכיפוף על הסף/מפתן בין המרפסת לחדר הפנימי. מים זורמים מתחת לסף וחודרים לדירה.. המלצה: הסרת הסף, ביצוע כיפוף יריעת איטום על מפתן הדלת, התקנת סף חדש עם אטימה. עלות משוערת: ₪800-₪2000 (ליחידה)', 'ת"י 1556 — איטום המרפסת חייב לעלות בכיפוף על הסף בגובה מינימלי של 5 ס"מ מעל מפלס הריצוף המוגמר', 'ת"י 1556 — איטום המרפסת חייב לעלות בכיפוף על הסף בגובה מינימלי של 5 ס"מ מעל מפלס הריצוף המוגמר', true, 'critical');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'איטום — מרפסות', '**נקז מרפסת סתום או חסר** — נקז המרפסת (גרגורי/ניקוז רצפתי) סתום, קטן מדי, או לא הותקן כלל. מים מצטברים על המרפסת ומזיקים לאיטום.. המלצה: התקנת נקז רצפתי בקוטר מינימלי 50 מ"מ עם חיבור למערכת הניקוז, כולל רשת לכידת פסולת. עלות משוערת: ₪600-₪1500 (ליחידה)', '**נקז מרפסת סתום או חסר** — נקז המרפסת (גרגורי/ניקוז רצפתי) סתום, קטן מדי, או לא הותקן כלל. מים מצטברים על המרפסת ומזיקים לאיטום.. המלצה: התקנת נקז רצפתי בקוטר מינימלי 50 מ"מ עם חיבור למערכת הניקוז, כולל רשת לכידת פסולת. עלות משוערת: ₪600-₪1500 (ליחידה)', 'ת"י 1556 — כל מרפסת חשופה חייבת נקודת ניקוז תקנית עם חיבור למערכת הניקוז של הבניין', 'ת"י 1556 — כל מרפסת חשופה חייבת נקודת ניקוז תקנית עם חיבור למערכת הניקוז של הבניין', true, 'medium');
